function ToastViewport() {
  const { toasts } = useToast();
  return (
    <Toast.Portal>
      <Toast.Viewport>
        {toasts.map((t) => (
          <Toast.Root key={t.id} toast={t}>
            <Toast.Content>
              <Toast.Title>{t.title}</Toast.Title>
              {t.description && <Toast.Description>{t.description}</Toast.Description>}
            </Toast.Content>
            {t.actionProps && <Toast.Action {...t.actionProps} />}
            <Toast.Close />
          </Toast.Root>
        ))}
      </Toast.Viewport>
    </Toast.Portal>
  );
}

function App() {
  return (
    <Toast.Provider>
      <YourAppContent />
      <ToastViewport />
    </Toast.Provider>
  );
}
